# ----------------------------- AUXILIARES -----------------------------------
def normaliza(txt):
    txt = unicodedata.normalize("NFD", str(txt))
    return "".join(c for c in txt if unicodedata.category(c) != "Mn").lower()

def fmt(v):
    if v is None:
        return ""
    if isinstance(v, float):
        return f"{v:g}".replace(".", ",")
    return str(v).strip()

def b64(caminho):
    ext = caminho.suffix.lower().lstrip(".")
    mime = "jpeg" if ext in ("jpg", "jpeg") else ext
    return f"data:image/{mime};base64," + base64.b64encode(caminho.read_bytes()).decode()

def parse_mangueira(valor):
    pares, diams, fams = [], set(), set()
    for seg in valor.split("/"):
        seg = seg.strip()
        if not seg:
            continue
        m = re.search(r"-([0O]?\d+)\s*$", seg)
        if m:
            d = int(m.group(1).replace("O", "0"))
            fam = re.sub(r"-[0O]?\d+\s*$", "", seg).strip()
            diams.add(d)
            if fam:
                fams.add(fam)
            pares.append((fam, d))
        elif seg:
            fams.add(seg)
    return pares, diams, fams

def token_ord(tok):
    if ":" in tok:
        d, v = tok.split(":")
        return (int(d), 1 + ORDEM_V16.index(v if v in ORDEM_V16 else "?"))
    return (int(tok), 0)

def rotulo_token(tok):
    if ":" in tok:
        v = VARIANTES_16.get(tok.split(":")[1])
        return f'-16 {v["curto"]}' if v else "-16 ?"
    return f"-{tok}"

def ponto_token(tok):
    if ":" in tok:
        chave = tok.split(":")[1]
        v = VARIANTES_16.get(chave)
        if v:
            extra = "border-color:rgba(0,0,0,.5);" if chave == "6k" else ""
            rot = f'{ROTULOS_DIAM[16]} — {v["rotulo"]}'
            return (f'<span class="pt" style="background:{v["cor"]};{extra}" '
                    f'title="{html.escape(rot)}"></span>')
        estilo = ("background:conic-gradient(#2e8b3a 0 118deg,rgba(45,45,45,.55) 118deg 122deg,"
                  "#e07b1f 122deg 238deg,rgba(45,45,45,.55) 238deg 242deg,"
                  "#f4f4ee 242deg 358deg,rgba(45,45,45,.55) 358deg 360deg)")
        return (f'<span class="pt" style="{estilo}" '
                f'title="Ø1&quot; — variante não mapeada (confira a legenda)"></span>')
    d = int(tok)
    cor = CORES_DIAM.get(d, "#999")
    return (f'<span class="pt" style="background:{cor}" '
            f'title="{html.escape(ROTULOS_DIAM.get(d, f"-{d}"))}"></span>')

def le_excel(arquivo):
    wb = load_workbook(arquivo, data_only=True)
    if ABA_CATALOGO not in wb.sheetnames:
        sys.exit(f"Aba '{ABA_CATALOGO}' não encontrada em {arquivo}")
    ws = wb[ABA_CATALOGO]
    linhas = ws.iter_rows(values_only=True)
    cabecalho = [fmt(c) for c in next(linhas)]
    sistemas, ordem = {}, []
    for row in linhas:
        reg = dict(zip(cabecalho, [fmt(v) for v in row]))
        if not any(reg.values()):
            continue
        chave = (reg.get(COL_SISTEMA, ""), reg.get(COL_ST, ""))
        if chave not in sistemas:
            sistemas[chave] = []
            ordem.append(chave)
        sistemas[chave].append(reg)
    colunas = [c for c in cabecalho if c and c not in COLUNAS_IGNORADAS
               and c not in (COL_SISTEMA, COL_ST)]
    return ordem, sistemas, colunas

